                     };
                 }
             }
        }

        // 3. Memory Intent
        // "สรุป ... ที่เราเคยเก็บไว้"
        if (/(เก็บ|เคย|สรุป).*(ไว้|ที่)/.test(q) && (q.includes("context") || q.includes("memory") || q.includes("จำ") || q.includes("เดิม"))) {
