                    text: `ไม่พบข้อมูลกฎหมายที่ตรงกับคำค้นหา "${args.query}"`
                }]
            };
        }

        // Format Output
        const formattedText = results.map(s => `## ${s.title}\n"${s.content}"`).join("\n\n");

        return {
            content: [{
                 type: "text" as const,
                 text: formattedText
            }]
